export const TX_ALL:TxItem[]=_R.map(([title,mid,hf],i)=>({
  id:`tx-${i}`,title,
  ministry:_M[mid][0],ministryEn:_M[mid][1],ministrySlug:_M[mid][2],icon:_M[mid][3],
  pdfUrl:_P[i]||'',hasForm:hf===1,fee:'',duration:''
}))
export const TX_WITH_FORMS:TxItem[]=TX_ALL.filter(t=>t.hasForm)

export function filterTxForms(ministrySlug:string,query:string):TxItem[]{
  let items=TX_WITH_FORMS
  if(ministrySlug&&ministrySlug!=='all')items=items.filter(t=>t.ministrySlug===ministrySlug)
  if(query.trim()){const q=query.toLowerCase();items=items.filter(t=>t.title.toLowerCase().includes(q)||t.ministry.includes(q))}
  return items
}
export function filterTxAll(ministrySlug:string,query:string,onlyForms=false):TxItem[]{
  let items=onlyForms?TX_WITH_FORMS:TX_ALL
  if(ministrySlug&&ministrySlug!=='all')items=items.filter(t=>t.ministrySlug===ministrySlug)
  if(query.trim()){const q=query.toLowerCase();items=items.filter(t=>t.title.toLowerCase().includes(q)||t.ministry.includes(q))}
  return items
}